import{_ as n,c as a,o as t,ai as o}from"./chunks/framework.BV5diS5Y.js";const p=JSON.parse('{"title":"KubeCon+CloudNativeCon India","description":"","frontmatter":{"title":"KubeCon+CloudNativeCon India","date":"2026-06-18","banner":"assets/events/20260429_kubecon_banner.svg","bannerMobile":"assets/events/20260618_kubecon_banner_mobile.svg","bannerSmall":"assets/events/20260618_kubecon_banner_small.svg","backgroundhex":"#889aa4ff","tags":["neonephos","kubecon"],"rssPubDate":"2026-04-29","published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/2026_06_18_KubeCon_India.md","filePath":"events/2026_06_18_KubeCon_India.md"}'),r={name:"events/2026_06_18_KubeCon_India.md"};function s(i,e,l,c,u,d){return t(),a("div",null,e[0]||(e[0]=[o(`<h1 id="neonephos-at-the-kubecon-cloudnativecon-india-2026-in-mumbai" tabindex="-1">NeoNephos at the KubeCon+CloudNativeCon India 2026 in Mumbai <a class="header-anchor" href="#neonephos-at-the-kubecon-cloudnativecon-india-2026-in-mumbai" aria-label="Permalink to &quot;NeoNephos at the KubeCon+CloudNativeCon India 2026 in Mumbai&quot;">​</a></h1><p>Open Source is important worldwide. That&#39;s why we will be present at the upcoming <a href="https://events.linuxfoundation.org/kubecon-cloudnativecon-india/" target="_blank" rel="noreferrer">KubeCon+CloudNativeCon India in Mumbai</a> with a talk!</p><hr><p><strong>Headline</strong>: <a href="https://kccncind2026.sched.com/event/2IW1x/kubernetes-plane-aerodynamics-breaking-the-architectural-sound-barrier-vasu-chandrasekhara-neonephos-stefan-schimanski-nvidia?iframe=yes&amp;w=100%25&amp;sidebar=yes&amp;bg=no" target="_blank" rel="noreferrer">Kubernetes Plane Aerodynamics: Breaking the Architectural Sound Barrier</a></p><p><strong>Speakers</strong>: Stefan Schimanski, NVIDIA &amp; Vasu Chandrasekhara NeoNephos</p><p>🗓 <strong>Date</strong>: June 18th, 2026 at 2:30 IST.</p><p><strong>Summary</strong>:</p><pre><code>We first trace the evolution of the &quot;aerodynamics&quot; of the K8s data, control, and work planes. As we dissect the architectural building blocks and controller archetypes of K8s, we discover the kubelet controller pattern as an universal design principle, with which we easily explain the unfolding of K8s Inception with Hosted Control Planes (HCP), where any control plane becomes a recursive workload in K8s itself.

Armed with these concepts we come to the ultimate, supersonic plane: KCP, the pure data and API plane.
Learn how to mentally decouple K8s from its underlying infrastructure and move toward a truly scalable, declarative API-first future. The next evolution in cloud-native. With KCP, and by treating KRM as a universal interface, we will show how you can benefit from the same pattern used to manage a single pod, to engineer global-scale platforms.

At each architecture evolution step, we accompany a demo and use case: from single clusters, vClusters, clusters with HCP, and KCP.
</code></pre><hr><p>Feel free to approach the speakers after the talk for a more personal introduction into NeoNephos and its associated topics!</p><p>👉 Don&#39;t miss out by securing your ticket <a href="https://events.linuxfoundation.org/kubecon-cloudnativecon-india/register/" target="_blank" rel="noreferrer">here</a>!</p>`,11)]))}const b=n(r,[["render",s]]);export{p as __pageData,b as default};
